// Enrichit les descriptions courtes/vides des produits Firestore via templates.
// 100% gratuit, pas d'appel API IA.
//
// Usage:
//   node scripts/enrich-descriptions.mjs           → dry-run sur 5 produits
//   node scripts/enrich-descriptions.mjs --sample=20 → dry-run sur 20 produits
//   node scripts/enrich-descriptions.mjs --write    → applique à tous les produits éligibles
//
// Critère : description totalement vide (n'écrase JAMAIS une description existante).
// Trace : ajoute `descriptionAutoGenerated: true` + `descriptionAutoAt: serverTimestamp`

import { config as dotenvConfig } from 'dotenv'
dotenvConfig({ path: '.env.local' })
import { initializeApp, cert, getApps } from 'firebase-admin/app'
import { getFirestore, FieldValue } from 'firebase-admin/firestore'

const projectId = process.env.FIREBASE_PROJECT_ID
const clientEmail = process.env.FIREBASE_CLIENT_EMAIL
const privateKey = process.env.FIREBASE_PRIVATE_KEY?.replace(/\\n/g, '\n')

if (!getApps().length) initializeApp({ credential: cert({ projectId, clientEmail, privateKey }) })
const db = getFirestore()

const args = process.argv.slice(2)
const WRITE = args.includes('--write')
const SHORT_MODE = args.includes('--short') // Mode concaténation : ne touche que les desc 1-49 char
const TRANSLATE_MODE = args.includes('--translate') // Mode trad : ajoute la version EN aux produits déjà auto-générés
const sampleArg = args.find(a => a.startsWith('--sample='))
const SAMPLE = sampleArg ? parseInt(sampleArg.split('=')[1], 10) : (WRITE ? Infinity : 5)

// Notes narratives variées par typologie (sacs, vêtements, bijoux)
