const EPOQUE_EN = {
  'années 60': 'the 60s',
  'années 70': 'the 70s',
  'années 80': 'the 80s',
  'années 90': 'the 90s',
  'années 2000 (esthétique Y2K)': 'the 2000s (Y2K aesthetic)',
}

function translate(dict, key, fallback) {
  if (!key) return fallback ?? key
  const k = key.trim().toLowerCase()
  return dict[k] || dict[key] || (fallback ?? key)
}

function pick(arr, seed) {
  let h = 0
  for (let i = 0; i < seed.length; i++) h = (h * 31 + seed.charCodeAt(i)) >>> 0
  return arr[h % arr.length]
}

function clean(s) {
  return (s || '').toString().trim()
}

function sentenceCase(s) {
  if (!s) return s
  // Si le texte est entièrement en majuscules (ou presque), on passe en sentence case
  const upperRatio = (s.match(/[A-ZÀ-Ý]/g) || []).length / Math.max(1, (s.match(/[a-zA-ZÀ-ÿ]/g) || []).length)
  if (upperRatio > 0.7) {
    return s.toLowerCase().replace(/(^|\.\s+|^|\s)([a-zà-ÿ])/g, (_, p, c) => p + c.toUpperCase())
  }
  return s.charAt(0).toUpperCase() + s.slice(1)
}

function isValidBrand(b) {
  if (!b) return false
  const t = b.trim()
  if (t.length < 2) return false
  if (/^[\/\-_.,;:]+$/.test(t)) return false
  return true
}

function cleanNom(nom, sku) {
  if (!nom) return ''
  let n = nom
  // Retire le SKU en préfixe
  if (sku) n = n.replace(new RegExp(`^${sku}\\s*[-–]\\s*`, 'i'), '')
  // Retire les tirets isolés et espaces multiples
  n = n.replace(/\s+[-–]\s+/g, ' ').replace(/\s+/g, ' ').trim()
  return sentenceCase(n)
}

// Détecte la typologie pour choisir les bonnes notes de style + termes
function detectType(catFirst, nomLower) {
  const sacRegex = /(sac|bag|pochette|cabas|tote|besace|bandouli|porte[-\s]?monnaie|porte[-\s]?cl)/i
  const bijouRegex = /(bague|bagues|collier|colliers|bracelet|boucles|earcuff|pendentif|cha[iî]ne|broche|gourmette|cr[eé]oles|cr[eé]oles|piercing)/i
  if (sacRegex.test(catFirst) || sacRegex.test(nomLower)) return 'sac'
  if (bijouRegex.test(catFirst) || bijouRegex.test(nomLower)) return 'bijou'
  return 'vetement'
}

// Détecte l'époque possible depuis le nom (Y2K, 70s, etc.)
function detectEpoque(nomLower) {
  if (/y2k/i.test(nomLower)) return 'années 2000 (esthétique Y2K)'
  if (/\b(70'?s?|seventies)\b/i.test(nomLower)) return 'années 70'
  if (/\b(80'?s?|eighties)\b/i.test(nomLower)) return 'années 80'
  if (/\b(90'?s?|nineties)\b/i.test(nomLower)) return 'années 90'
  if (/\b60'?s?\b/i.test(nomLower)) return 'années 60'
  return ''
}

function formatField(label, value) {
  if (!value) return ''
  return `• ${label} : ${value}`
}

function generate(p) {
  const seed = p.id || p.sku || 'x'
  const catRawLabel = clean(typeof p.categorie === 'object' ? p.categorie?.label : p.categorie)
  // Nettoie le préfixe trigramme ("EQU - ", "MAZ - ", etc.)
  const cat = catRawLabel.replace(/^[A-Z]{2,5}\s*-\s*/, '').trim()
  const catRaw = cat.replace(/\s*\/\s*/g, ' ou ').trim().toLowerCase() || 'pièce'
  const catFirst = catRaw.split(/[\s/]/).filter(Boolean)[0] || 'pièce'
  const marqueRaw = clean(p.marque)
  const marque = isValidBrand(marqueRaw) ? marqueRaw : ''
  const taille = clean(p.taille).replace(/^taille\s+/i, '').trim()
  const couleur = clean(p.color)
  const matiere = clean(p.material)
  const madeIn = clean(p.madeIn)
  const nom = cleanNom(p.nom, p.sku)
  const nomLower = nom.toLowerCase()
  const type = detectType(catFirst, nomLower)
  const epoque = detectEpoque(nomLower)

  // ====== BLOC 1 : description narrative (2-3 phrases) ======

  // Phrase 1 — la pièce
  let phrase1
  if (nom) {
    const nomHasBrand = marque && nomLower.includes(marque.toLowerCase())
    const nomHasCat = catFirst !== 'pièce' && nomLower.includes(catFirst)
    const prefix = nomHasCat ? '' : (catFirst.charAt(0).toUpperCase() + catFirst.slice(1) + ' ')
    const brandPart = (marque && !nomHasBrand) ? `${marque} — ` : ''
    phrase1 = `${prefix}${brandPart}${nom}`.replace(/\s+/g, ' ').trim()
  } else {
    const parts = [catFirst.charAt(0).toUpperCase() + catFirst.slice(1)]
    if (marque) parts.push(marque)
    phrase1 = parts.join(' ')
  }
  if (!/[.!?]$/.test(phrase1)) phrase1 += '.'

  // Phrase 2 — détails matière/couleur/époque (séparés correctement)
  let phrase2 = ''
  const phraseParts = []
  const matiereInNom = matiere && nomLower.includes(matiere.toLowerCase())
  const couleurInNom = couleur && nomLower.includes(couleur.toLowerCase())
  if (matiere && !matiereInNom) {
    phraseParts.push(`Réalisée en ${matiere.toLowerCase()}`)
  }
  if (couleur && !couleurInNom) {
    if (phraseParts.length > 0) {
      phraseParts.push(`coloris ${couleur.toLowerCase()}`)
    } else {
      phraseParts.push(`Coloris ${couleur.toLowerCase()}`)
    }
  }
  if (epoque) {
    phraseParts.push(`pièce des ${epoque}`)
  }
  if (madeIn) {
    // "Made in Italy" → "confectionnée en Italie"
    const m = madeIn.replace(/^Made in\s+/i, '').trim()
    if (m) phraseParts.push(`confectionnée en ${m}`)
  }
  phrase2 = phraseParts.join(', ')
  if (phrase2) {
    phrase2 = phrase2.charAt(0).toUpperCase() + phrase2.slice(1)
    if (!/[.!?]$/.test(phrase2)) phrase2 += '.'
  }

  // Phrase 3 — note de style (selon type)
  const notes = type === 'sac' ? NOTES_SAC : type === 'bijou' ? NOTES_BIJOU : NOTES_VETEMENT
  const phrase3 = pick(notes, seed)

  // La description Firestore = uniquement le bloc narratif (3 phrases max).
  // Les caractéristiques et le bloc Nouvelle Rive sont rendus par ProduitClient.tsx.
  return [phrase1, phrase2, phrase3].filter(Boolean).join(' ')
}

function generateEN(p) {
  const seed = p.id || p.sku || 'x'
  const catRawLabel = clean(typeof p.categorie === 'object' ? p.categorie?.label : p.categorie)
  const catFR = catRawLabel.replace(/^[A-Z]{2,5}\s*-\s*/, '').trim().toLowerCase() || 'pièce'
  const catFirstFR = catFR.split(/[\s/]/).filter(Boolean)[0] || 'pièce'
  const catFirstEN = translate(CATEGORY_EN, catFirstFR, catFirstFR)
  const marqueRaw = clean(p.marque)
  const marque = isValidBrand(marqueRaw) ? marqueRaw : ''
  const taille = clean(p.taille).replace(/^taille\s+/i, '').trim()
  const couleur = clean(p.color)
  const matiere = clean(p.material)
  const madeIn = clean(p.madeIn)
  const nom = cleanNom(p.nom, p.sku)
  const nomLower = nom.toLowerCase()
  const type = detectType(catFirstFR, nomLower)
  const epoqueFR = detectEpoque(nomLower)
  const epoqueEN = epoqueFR ? translate(EPOQUE_EN, epoqueFR, epoqueFR) : ''

  // Phrase 1 EN — la pièce
  let phrase1
  if (nom) {
    const nomHasBrand = marque && nomLower.includes(marque.toLowerCase())
    const nomHasCat = catFirstEN !== 'piece' && (nomLower.includes(catFirstEN.toLowerCase()) || nomLower.includes(catFirstFR))
    const prefix = nomHasCat ? '' : (catFirstEN.charAt(0).toUpperCase() + catFirstEN.slice(1) + ' ')
    const brandPart = (marque && !nomHasBrand) ? `${marque} — ` : ''
    phrase1 = `${prefix}${brandPart}${nom}`.replace(/\s+/g, ' ').trim()
  } else {
    const parts = [catFirstEN.charAt(0).toUpperCase() + catFirstEN.slice(1)]
    if (marque) parts.push(marque)
    phrase1 = parts.join(' ')
  }
  if (!/[.!?]$/.test(phrase1)) phrase1 += '.'

  // Phrase 2 EN — détails
  let phrase2 = ''
  const phraseParts = []
  const matiereInNom = matiere && nomLower.includes(matiere.toLowerCase())
  const couleurInNom = couleur && nomLower.includes(couleur.toLowerCase())
  if (matiere && !matiereInNom) {
    const m = translate(MATERIAL_EN, matiere.toLowerCase(), matiere.toLowerCase())
    phraseParts.push(`Made of ${m}`)
  }
  if (couleur && !couleurInNom) {
    const c = translate(COLOR_EN, couleur.toLowerCase(), couleur.toLowerCase())
    if (phraseParts.length > 0) phraseParts.push(`${c} hue`)
    else phraseParts.push(`${c.charAt(0).toUpperCase() + c.slice(1)} hue`)
  }
  if (epoqueEN) {
    phraseParts.push(`piece from ${epoqueEN}`)
  }
  if (madeIn) {
    const country = madeIn.replace(/^Made in\s+/i, '').trim()
    const countryEN = translate(COUNTRY_EN, country, country)
    if (countryEN) phraseParts.push(`crafted in ${countryEN}`)
  }
  phrase2 = phraseParts.join(', ')
  if (phrase2) {
    phrase2 = phrase2.charAt(0).toUpperCase() + phrase2.slice(1)
    if (!/[.!?]$/.test(phrase2)) phrase2 += '.'
  }

  // Phrase 3 EN — note de style
  const notesEN = type === 'sac' ? NOTES_SAC_EN : type === 'bijou' ? NOTES_BIJOU_EN : NOTES_VETEMENT_EN
  const phrase3 = pick(notesEN, seed)

  return [phrase1, phrase2, phrase3].filter(Boolean).join(' ')
}

const snap = await db.collection('produits').get()
const eligibles = snap.docs
  .map(d => ({ id: d.id, ...d.data() }))
  .filter(p => {
    if (p.statut === 'supprime' || p.statut === 'retour' || p.vendu === true) return false
    if (TRANSLATE_MODE) {
      // On ajoute la trad EN aux produits auto-générés qui n'ont pas encore de drapeau EN
      if (!p.descriptionAutoGenerated) return false
      const desc = (p.description || '')
      return !desc.includes('🇬🇧')
    }
    const len = (p.description || '').trim().length
    if (SHORT_MODE) return len > 0 && len < 50
    return len === 0
  })

const labelMode = TRANSLATE_MODE
  ? 'auto-générés sans trad EN — à enrichir avec drapeau 🇬🇧'
  : SHORT_MODE
    ? 'avec description courte (1-49 char) à enrichir par concaténation'
    : 'sans description (existantes préservées)'
console.log(`📋 ${snap.size} produits, ${eligibles.length} ${labelMode}`)

const target = eligibles.slice(0, SAMPLE === Infinity ? eligibles.length : SAMPLE)
console.log(`${WRITE ? '✏️  Écriture' : '🔍 Dry-run'} sur ${target.length} produits...\n`)

const results = []
let done = 0
for (const p of target) {
  let description
  if (TRANSLATE_MODE) {
    // Mode trad : on garde la description actuelle et on ajoute le bloc EN à la fin
    const actuel = (p.description || '').trim()
    const narratifEN = generateEN(p)
    description = `${actuel}\n\n🇬🇧 ${narratifEN}`
  } else {
    const narratif = generate(p)
    const ancienne = (p.description || '').trim()
    description = SHORT_MODE && ancienne ? `${ancienne}\n\n${narratif}` : narratif
  }
  if (WRITE) {
    await db.collection('produits').doc(p.id).update({
      description,
      descriptionAutoGenerated: true,
      descriptionAutoAt: FieldValue.serverTimestamp(),
    })
    done++
    if (done % 50 === 0) process.stdout.write(`\r✓ ${done} / ${target.length}`)
  }
  results.push({ id: p.id, sku: p.sku, nom: p.nom, marque: p.marque, ancienne: p.description, description })
}
if (WRITE) process.stdout.write(`\r✓ ${done} / ${target.length}\n`)

if (!WRITE) {
  console.log('=== APERÇUS ===\n')
  for (const t of results) {
    console.log(`▶ ${t.sku} — ${t.marque || '(sans marque)'} — ${t.nom}`)
    if (t.ancienne) console.log(`   AVANT : ${t.ancienne}`)
    console.log(`   APRÈS : ${t.description}`)
    console.log()
  }
  console.log(`Pour appliquer aux ${eligibles.length} produits éligibles :`)
  console.log(`  node scripts/enrich-descriptions.mjs --write`)
} else {
  console.log(`\n✅ ${results.length} produits enrichis dans Firestore`)
}

process.exit(0)
